   134	int trx_eth_write_raw(openair0_device *device, openair0_timestamp timestamp, void **buff, int nsamps,int cc, int flags) {
   135	  
   136	  int bytes_sent=0;
   137	  eth_state_t *eth = (eth_state_t*)device->priv;
   138	  int sendto_flag =0;
   139	  int i=0;
   140	  //sendto_flag|=flags;
   141	
   142	  eth->tx_nsamps=nsamps;
   143	  int pktsize;
   144	  if (eth->compression == ALAW_COMPRESS) {
   145	    pktsize = RAW_PACKET_SIZE_BYTES_ALAW(nsamps);
   146	  } else {
   147	    pktsize = RAW_PACKET_SIZE_BYTES(nsamps);
   148	  }   
   149	  for (i=0;i<cc;i++) {	
   150	    /* buff[i] points to the position in tx buffer where the payload to be sent is
   151	       buff2 points to the position in tx buffer where the packet header will be placed */
   152	    void *buff2 = (void*)(buff[i]-APP_HEADER_SIZE_BYTES-MAC_HEADER_SIZE_BYTES); 
   153	    
   154	    /* we don't want to ovewrite with the header info the previous tx buffer data so we store it*/
   155	    struct ether_header temp =  *(struct ether_header *)buff2;
   156	    int32_t temp0 = *(int32_t *)(buff2 + MAC_HEADER_SIZE_BYTES);
   157	    openair0_timestamp  temp1 = *(openair0_timestamp *)(buff2 + MAC_HEADER_SIZE_BYTES + sizeof(int32_t));
   158	    
   159	    bytes_sent = 0;
   160	    memcpy(buff2,(void*)&eth->ehd,MAC_HEADER_SIZE_BYTES);
   161	    *(int16_t *)(buff2 + MAC_HEADER_SIZE_BYTES + sizeof(int16_t))=1+(i<<1);
   162	    *(openair0_timestamp *)(buff2 + MAC_HEADER_SIZE_BYTES + sizeof(int32_t)) = timestamp;  
   163	
   164	    /*printf("[RRU]write mod_%d %d , len %d, buff %p \n",
   165	      Mod_id,eth->sockfd[Mod_id],RAW_PACKET_SIZE_BYTES(nsamps), buff2);*/
   166	    
   167	    while(bytes_sent < pktsize) {
   168	
   169	      /* Send packet */
   170	
   171	      bytes_sent += send(eth->sockfdd[cc % eth->num_fd],
   172				 buff2, 
   173				 pktsize,
   174				 sendto_flag);
   175	      if ( bytes_sent == -1) {
   176		eth->num_tx_errors++;
   177		perror("ETHERNET WRITE: ");
   178		exit(-1);
   179	      } else {
   180	
   181	      eth->tx_actual_nsamps=bytes_sent>>2;
   182	      eth->tx_count++;
   183	      }
   184	    }    			    
   185	    
   186	  /* tx buffer values restored */  
   187	    *(struct ether_header *)buff2 = temp;
   188	    *(int32_t *)(buff2 + MAC_HEADER_SIZE_BYTES) = temp0;
   189	    *(openair0_timestamp *)(buff2 + MAC_HEADER_SIZE_BYTES + sizeof(int32_t)) = temp1;
   190	  }
   191	  return (bytes_sent-APP_HEADER_SIZE_BYTES-MAC_HEADER_SIZE_BYTES)>>2;
   192	}
